evaluators.evaluation_logic:
const checkpoints = [];

const quoteRequests = JSON.parse(localStorage.getItem('quote_requests') || '[]');
const serviceOptions = JSON.parse(localStorage.getItem('service_level_options') || '[]');

const MAX_BUDGET = 15000;

// Find all service options for slope stability embankments that include stability modeling and are within the budget
const modelingOptions = serviceOptions.filter(function (opt) {
  return opt && opt.serviceType === 'slope_stability_embankments' && !!opt.includesStabilityModeling && typeof opt.price === 'number' && opt.price <= MAX_BUDGET;
});

let cheapestModelingOption = null;
for (let i = 0; i < modelingOptions.length; i++) {
  const opt = modelingOptions[i];
  if (!cheapestModelingOption || opt.price < cheapestModelingOption.price) {
    cheapestModelingOption = opt;
  }
}

// Candidate quotes: correct service/project type, Denver, 2025 construction start, budget within limit
const candidateQuotes = quoteRequests.filter(function (q) {
  if (!q) return false;
  if (q.serviceType !== 'slope_stability_embankments') return false;
  if (q.projectType !== 'highway_roadway') return false;
  if (!q.locationCity || String(q.locationCity).toLowerCase() !== 'denver') return false;
  if (typeof q.maxBudgetUsd !== 'number' || q.maxBudgetUsd > MAX_BUDGET) return false;
  if (!q.anticipatedConstructionStartDate) return false;
  const t = Date.parse(q.anticipatedConstructionStartDate);
  if (isNaN(t)) return false;
  const d = new Date(t);
  const year = (d.getUTCFullYear ? d.getUTCFullYear() : d.getFullYear());
  if (year !== 2025) return false;
  return true;
});

// Among candidate quotes, find those that selected a modeling-including option within budget
const candidateWithModeling = candidateQuotes.filter(function (q) {
  const opt = serviceOptions.find(function (o) { return o && o.id === q.selectedServiceLevelId; });
  return !!opt && opt.serviceType === 'slope_stability_embankments' && !!opt.includesStabilityModeling && typeof opt.price === 'number' && opt.price <= MAX_BUDGET && opt.price <= q.maxBudgetUsd;
});

// Among candidate quotes, find those that selected the globally cheapest qualifying modeling option
const candidateWithCheapest = candidateQuotes.filter(function (q) {
  if (!cheapestModelingOption) return false;
  return q.selectedServiceLevelId === cheapestModelingOption.id;
});

// CP1 (0.35): User submitted at least one quote with correct service/project type, Denver, 2025 start, and budget ≤ 15,000
checkpoints.push({ passed: candidateQuotes.length > 0, weight: 0.35 });

// CP2 (0.30): At least one such quote selected a service level that DOES include stability modeling and fits within the stated budget and global budget
checkpoints.push({ passed: candidateWithModeling.length > 0, weight: 0.30 });

// CP3 (0.35): At least one such quote selected the CHEAPEST available modeling-including option under $15,000
checkpoints.push({ passed: !!cheapestModelingOption && candidateWithCheapest.length > 0, weight: 0.35 });

return checkpoints.reduce(function (sum, cp) { return sum + (cp.passed ? cp.weight : 0); }, 0);

const checkpoints = [];

const plans = JSON.parse(localStorage.getItem('saved_investigation_plans') || '[]');
const packages = JSON.parse(localStorage.getItem('investigation_packages') || '[]');

const TARGET_PROJECT_NAME = 'Headquarters foundation study';
const MAX_PRICE = 12000;

function isQualifyingPackage(pkg) {
  if (!pkg) return false;
  if (pkg.projectType !== 'building_foundations') return false;
  if (typeof pkg.price !== 'number' || pkg.price > MAX_PRICE) return false;
  if (!pkg.includesCptSoundings) return false;
  if (!pkg.includesConsolidationTesting) return false;
  if (pkg.isActive === false) return false;
  return true;
}

// Plans with the correct project name and qualifying package
const candidatePlans = plans.filter(function (p) {
  if (!p || p.projectName !== TARGET_PROJECT_NAME) return false;
  const pkg = packages.find(function (k) { return k && k.id === p.investigationPackageId; });
  return isQualifyingPackage(pkg);
});

// Find the cheapest qualifying package overall
const qualifyingPkgs = packages.filter(isQualifyingPackage);
let cheapestPkg = null;
for (let i = 0; i < qualifyingPkgs.length; i++) {
  const pkg = qualifyingPkgs[i];
  if (!cheapestPkg || pkg.price < cheapestPkg.price) {
    cheapestPkg = pkg;
  }
}

// CP1 (0.50): At least one saved plan named 'Headquarters foundation study' uses a building_foundations package with CPT and consolidation testing priced ≤ $12,000
checkpoints.push({ passed: candidatePlans.length > 0, weight: 0.50 });

// CP2 (0.50): That plan uses the CHEAPEST qualifying package under $12,000
const usesCheapest = !!cheapestPkg && candidatePlans.some(function (p) { return p.investigationPackageId === cheapestPkg.id; });
checkpoints.push({ passed: usesCheapest, weight: 0.50 });

return checkpoints.reduce(function (sum, cp) { return sum + (cp.passed ? cp.weight : 0); }, 0);

const checkpoints = [];

const pf = JSON.parse(localStorage.getItem('task3_projectFilters') || 'null');
const openedProjectId = localStorage.getItem('task3_openedProjectId') || null;
const projects = JSON.parse(localStorage.getItem('project_case_studies') || '[]');

const filtersObj = pf && pf.filters ? pf.filters : null;
const sortBy = pf ? pf.sortBy : null;

// Correct filter criteria: sector=commercial_buildings, foundationType=pile_foundations, minProjectValueUsd ≥ 5,000,000
const hasCorrectFilters = !!filtersObj && filtersObj.sector === 'commercial_buildings' && filtersObj.foundationType === 'pile_foundations' && filtersObj.minProjectValueUsd != null && Number(filtersObj.minProjectValueUsd) >= 5000000;

const openedProject = projects.find(function (p) { return p && p.id === openedProjectId; }) || null;

// Opened project must be commercial, pile foundations, and value > $5M
const openedQualifies = !!openedProject && openedProject.sector === 'commercial_buildings' && openedProject.foundationType === 'pile_foundations' && typeof openedProject.projectValueUsd === 'number' && openedProject.projectValueUsd > 5000000;

// CP1 (0.30): User applied filters specifically for commercial building projects with pile foundations and min project value ≥ $5M
checkpoints.push({ passed: hasCorrectFilters, weight: 0.30 });

// CP2 (0.30): User opened a project whose sector is commercial_buildings, foundationType is pile_foundations, and value exceeds $5M
checkpoints.push({ passed: openedQualifies, weight: 0.30 });

// CP3 (0.40): Both correct filters were used AND the opened project meets those criteria
checkpoints.push({ passed: hasCorrectFilters && openedQualifies, weight: 0.40 });

return checkpoints.reduce(function (sum, cp) { return sum + (cp.passed ? cp.weight : 0); }, 0);

const checkpoints = [];

const pf = JSON.parse(localStorage.getItem('task4_resourceFilters') || 'null');
const downloadedResourceId = localStorage.getItem('task4_downloadedResourceId') || null;
const resources = JSON.parse(localStorage.getItem('resources') || '[]');

const filtersObj = pf && pf.filters ? pf.filters : null;
const sortBy = pf ? pf.sortBy : null;

const MIN_DATE_STR = '2022-01-01';
const MIN_DATE = Date.parse(MIN_DATE_STR);

// Correct filters: guides_checklists, topic=retaining_walls, level=intermediate, publishedDateStart ≥ 2022-01-01, sortBy=published_date_newest
let hasCorrectFilter = false;
if (filtersObj) {
  const publishedStart = filtersObj.publishedDateStart ? Date.parse(filtersObj.publishedDateStart) : NaN;
  hasCorrectFilter = filtersObj.resourceType === 'guides_checklists' && filtersObj.topic === 'retaining_walls' && filtersObj.level === 'intermediate' && !isNaN(publishedStart) && publishedStart >= MIN_DATE && sortBy === 'published_date_newest';
}

const downloaded = resources.find(function (r) { return r && r.id === downloadedResourceId; }) || null;

// Downloaded resource must be an intermediate retaining wall checklist from 2022 or later
let downloadedQualifies = false;
if (downloaded && downloaded.publishedDate) {
  const pub = Date.parse(downloaded.publishedDate);
  downloadedQualifies = downloaded.resourceType === 'guides_checklists' && downloaded.topic === 'retaining_walls' && (downloaded.level === 'intermediate' || downloaded.level === 'all_levels') && !!downloaded.isChecklist && !isNaN(pub) && pub >= MIN_DATE;
}

// Find newest qualifying retaining wall checklist (intermediate/all_levels, 2022+)
let newest = null;
for (let i = 0; i < resources.length; i++) {
  const r = resources[i];
  if (!r || !r.publishedDate) continue;
  const pub = Date.parse(r.publishedDate);
  if (isNaN(pub)) continue;
  const qualifies = r.resourceType === 'guides_checklists' && r.topic === 'retaining_walls' && (r.level === 'intermediate' || r.level === 'all_levels') && !!r.isChecklist && pub >= MIN_DATE;
  if (!qualifies) continue;
  if (!newest || pub > Date.parse(newest.publishedDate)) {
    newest = r;
  }
}

const isNewest = downloadedQualifies && !!newest && downloaded.id === newest.id;

// CP1 (0.30): User applied correct filters and sorted by newest first
checkpoints.push({ passed: hasCorrectFilter, weight: 0.30 });

// CP2 (0.30): User downloaded a retaining wall checklist that matches the filtered criteria (intermediate level, 2022+, checklist)
checkpoints.push({ passed: downloadedQualifies, weight: 0.30 });

// CP3 (0.40): The downloaded checklist is the NEWEST qualifying retaining wall design checklist and filters were correct
checkpoints.push({ passed: hasCorrectFilter && isNewest, weight: 0.40 });

return checkoints.reduce(function (sum, cp) { return sum + (cp.passed ? cp.weight : 0); }, 0);

const checkpoints = [];

const bookings = JSON.parse(localStorage.getItem('consultation_bookings') || '[]');
const slots = JSON.parse(localStorage.getItem('consultation_availability_slots') || '[]');

function isMarch2025(dateStr) {
  const t = Date.parse(dateStr);
  if (isNaN(t)) return false;
  const d = new Date(t);
  const y = d.getUTCFullYear ? d.getUTCFullYear() : d.getFullYear();
  const m = (d.getUTCMonth ? d.getUTCMonth() : d.getMonth()) + 1;
  return y === 2025 && m === 3;
}

function isWithinTimeWindow(dateStr) {
  if (!dateStr || dateStr.length < 16) return false;
  const timePart = dateStr.substring(11, 16); // 'HH:MM'
  return timePart >= '10:00' && timePart <= '10:30';
}

// Candidate bookings that meet all task criteria
const candidateBookings = bookings.filter(function (b) {
  if (!b) return false;
  if (b.meetingType !== 'virtual_meeting') return false;
  if (b.specialty !== 'foundation_design') return false;
  if (b.projectStage !== 'concept_early_design') return false;
  if (b.name !== 'Alex Martinez') return false;
  if (b.email !== 'alex.martinez@example.com') return false;
  if (!b.startDateTime || !b.endDateTime) return false;
  if (!isMarch2025(b.startDateTime)) return false;
  if (!isWithinTimeWindow(b.startDateTime)) return false;
  const dtStart = Date.parse(b.startDateTime);
  const dtEnd = Date.parse(b.endDateTime);
  if (isNaN(dtStart) || isNaN(dtEnd)) return false;
  const durationMinutes = (dtEnd - dtStart) / (60 * 1000);
  if (Math.round(durationMinutes) !== 30) return false;
  return true;
});

// Among those, require that the referenced availability slot exists, matches the type/specialty and is marked booked
const candidateWithValidSlot = candidateBookings.filter(function (b) {
  const slot = slots.find(function (s) { return s && s.id === b.availabilitySlotId; });
  if (!slot) return false;
  if (slot.meetingType !== 'virtual_meeting') return false;
  if (slot.specialty !== 'foundation_design') return false;
  if (slot.startDateTime !== b.startDateTime || slot.endDateTime !== b.endDateTime) return false;
  if (!slot.isBooked) return false;
  return true;
});

// CP1 (0.70): At least one booking exists that is a 30-minute March 2025 virtual foundation design consultation between 10:00 and 10:30 for Alex Martinez with the given email
checkpoints.push({ passed: candidateBookings.length > 0, weight: 0.70 });

// CP2 (0.30): That booking is tied to a valid availability slot now marked as booked with matching time and specialty
checkpoints.push({ passed: candidateWithValidSlot.length > 0, weight: 0.30 });

return checkpoints.reduce(function (sum, cp) { return sum + (cp.passed ? cp.weight : 0); }, 0);

const checkpoints = [];

const results = JSON.parse(localStorage.getItem('bearing_capacity_results') || '[]');

// Saved results that match the specified inputs and project name
const candidateResults = results.filter(function (r) {
  if (!r) return false;
  if (r.projectName !== 'Office Tower A') return false;
  if (r.soilType !== 'medium_dense_sand') return false;
  if (typeof r.footingWidth !== 'number' || r.footingWidth !== 2.0) return false;
  if (r.footingWidthUnit !== 'm') return false;
  if (typeof r.footingDepth !== 'number' || r.footingDepth !== 1.5) return false;
  if (r.footingDepthUnit !== 'm') return false;
  if (typeof r.factorOfSafety !== 'number' || r.factorOfSafety !== 3) return false;
  return true;
});

// Among these, confirm they are linked to the Bearing Capacity Calculator tool definition
const candidateWithTool = candidateResults.filter(function (r) {
  return r.toolId === 'bearing_capacity_calculator';
});

// CP1 (0.60): At least one saved bearing capacity result for 'Office Tower A' uses medium dense sand, B=2.0 m, D=1.5 m, FOS=3
checkpoints.push({ passed: candidateResults.length > 0, weight: 0.60 });

// CP2 (0.40): That result is associated with the Bearing Capacity Calculator tool
checkpoints.push({ passed: candidateWithTool.length > 0, weight: 0.40 });

return checkpoints.reduce(function (sum, cp) { return sum + (cp.passed ? cp.weight : 0); }, 0);

const checkpoints = [];

const subs = JSON.parse(localStorage.getItem('newsletter_subscriptions') || '[]');

const sub = subs.find(function (s) { return s && s.email === 'client.geotech@example.com'; }) || null;

let topicsOk = false;
let freqOk = false;
let roleOk = false;

if (sub) {
  const topics = Array.isArray(sub.topics) ? sub.topics : [];
  const hasSlope = topics.indexOf('slope_stability') !== -1;
  const hasDeep = topics.indexOf('deep_foundations') !== -1;
  const hasGroundImprovement = topics.indexOf('ground_improvement') !== -1;
  topicsOk = hasSlope && hasDeep && !hasGroundImprovement;
  freqOk = sub.emailFrequency === 'monthly';
  roleOk = sub.professionalRole === 'consulting_engineer';
}

// CP1 (0.70): Subscription for this email selects slope_stability and deep_foundations, excludes ground_improvement, and uses monthly frequency
checkpoints.push({ passed: !!sub && topicsOk && freqOk, weight: 0.70 });

// CP2 (0.30): Subscription sets professionalRole to consulting_engineer
checkpoints.push({ passed: !!sub && roleOk, weight: 0.30 });

return checkpoints.reduce(function (sum, cp) { return sum + (cp.passed ? cp.weight : 0); }, 0);

const checkpoints = [];

const shortlist = JSON.parse(localStorage.getItem('project_team_shortlist') || '[]');
const members = JSON.parse(localStorage.getItem('team_members') || '[]');

function hasRequiredSkill(member) {
  const skills = Array.isArray(member.keySkills) ? member.keySkills : [];
  const kw1 = 'slope stability';
  const kw2 = 'landslide analysis';
  let found = false;
  for (let i = 0; i < skills.length; i++) {
    const s = String(skills[i]).toLowerCase();
    if (s.indexOf(kw1) !== -1 || s.indexOf(kw2) !== -1) {
      found = true;
      break;
    }
  }
  return found;
}

function qualifiesMember(member) {
  if (!member) return false;
  if (member.region !== 'west') return false;
  if (member.discipline !== 'geotechnical_engineering') return false;
  if (typeof member.yearsOfExperience !== 'number' || member.yearsOfExperience < 10) return false;
  if (!hasRequiredSkill(member)) return false;
  return true;
}

// Map shortlist items to members and see which shortlisted members qualify
const qualifyingShortlistedIds = [];
for (let i = 0; i < shortlist.length; i++) {
  const item = shortlist[i];
  const member = members.find(function (m) { return m && m.id === item.teamMemberId; });
  if (qualifiesMember(member)) {
    if (qualifyingShortlistedIds.indexOf(member.id) === -1) {
      qualifyingShortlistedIds.push(member.id);
    }
  }
}

// CP1 (0.40): At least one qualifying West-region geotechnical slope/landslide expert is on the shortlist
checkpoints.push({ passed: qualifyingShortlistedIds.length >= 1, weight: 0.40 });

// CP2 (0.60): At least three such qualifying experts are on the shortlist
checkpoints.push({ passed: qualifyingShortlistedIds.length >= 3, weight: 0.60 });

return checkpoints.reduce(function (sum, cp) { return sum + (cp.passed ? cp.weight : 0); }, 0);
